 35â†’    private val uiHelpers: UiHelpers
 36â†’) : PagedListAdapter<PostListItemType, ViewHolder>(PostListDiffItemCallback) {
 37â†’    private val layoutInflater: LayoutInflater = LayoutInflater.from(context)
 38â†’    private var itemLayoutType: PostListViewLayoutType = PostListViewLayoutType.defaultValue
 39â†’
 40â†’    override fun getItemViewType(position: Int): Int {
 41â†’        return when (getItem(position)) {
 42â†’            is EndListIndicatorItem -> VIEW_TYPE_ENDLIST_INDICATOR
 43â†’            is PostListItemUiState -> {
 44â†’                when (itemLayoutType) {
 45â†’                    STANDARD -> VIEW_TYPE_POST
 46â†’                    COMPACT -> VIEW_TYPE_POST_COMPACT
 47â†’                }
 48â†’            }
 49â†’            is LoadingItem, null -> {
 50â†’                when (itemLayoutType) {
 51â†’                    STANDARD -> VIEW_TYPE_LOADING
 52â†’                    COMPACT -> VIEW_TYPE_LOADING_COMPACT
 53â†’                }
 54â†’            }
 55â†’        }
 56â†’    }
 57â†’
 58â†’    @Suppress("UseCheckOrError")
 59â†’    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ViewHolder {
 60â†’        return when (viewType) {
 61â†’            VIEW_TYPE_ENDLIST_INDICATOR -> {
 62â†’                val view = layoutInflater.inflate(R.layout.list_with_fab_endlist_indicator, parent, false)
 63â†’                EndListViewHolder(view)
 64â†’            }
 65â†’            VIEW_TYPE_LOADING -> {
 66â†’                val view = layoutInflater.inflate(R.layout.post_list_item_skeleton, parent, false)
 67â†’                LoadingViewHolder(view)
 68â†’            }
 69â†’            VIEW_TYPE_LOADING_COMPACT -> {
 70â†’                val view = layoutInflater.inflate(R.layout.post_list_item_skeleton_compact, parent, false)
 71â†’                LoadingViewHolder(view)
 72â†’            }
 73â†’            VIEW_TYPE_POST -> {
 74â†’                PostListItemViewHolder.Standard(parent, imageManager, uiHelpers)
 75â†’            }
 76â†’            VIEW_TYPE_POST_COMPACT -> {
 77â†’                PostListItemViewHolder.Compact(parent, imageManager, uiHelpers)
 78â†’            }
 79â†’            else -> {
 80â†’                // Fail fast if a new view type is added so the we can handle it
 81â†’                throw IllegalStateException("The view type '$viewType' needs to be handled")
 82â†’            }
 83â†’        }
 84â†’    }
 85â†’
 86â†’    override fun onBindViewHolder(holder: ViewHolder, position: Int) {
 87â†’        // The only holders that require special setup are PostListItemViewHolder and LoadingViewHolder subclasses
 88â†’        if (holder is PostListItemViewHolder) {
 89â†’            val item = getItem(position)
 90â†’            assert(item is PostListItemUiState) {
 91â†’                "If we are presenting PostViewHolder, the item has to be of type PostListItemUiState " +
 92â†’                        "for position: $position"
 93â†’            }
 94â†’            holder.onBind((item as PostListItemUiState))
 95â†’        }
 96â†’        if (holder is LoadingViewHolder) {
 97â†’            val item = getItem(position)
 98â†’            assert(item is LoadingItem?) {
 99â†’                "If we are presenting LoadingViewHolder, the item has to be of type LoadingItem " +
100â†’                        "for position: $position"
101â†’            }
102â†’            // getItem returns the item, or NULL, if a null placeholder is at the specified position.
103â†’            item?.let { holder.onBind((item as LoadingItem)) }
104â†’        }
105â†’    }
