107â†’    fun updateItemLayoutType(updatedItemLayoutType: PostListViewLayoutType): Boolean {
108â†’        if (updatedItemLayoutType == itemLayoutType) {
109â†’            return false
110â†’        }
111â†’        itemLayoutType = updatedItemLayoutType
112â†’        notifyDataSetChanged()
113â†’        return true
114â†’    }
