 445â†’    public static ReaderTag getReaderTag() {
 446â†’        String tagName = getString(DeletablePrefKey.READER_TAG_NAME);
 447â†’        if (TextUtils.isEmpty(tagName)) {
 448â†’            return null;
 449â†’        }
 450â†’        int tagType = getInt(DeletablePrefKey.READER_TAG_TYPE);
 451â†’
 452â†’        boolean wasFollowing = false;
 453â†’
 454â†’        // The intention here is to check if the `DeletablePrefKey.READER_TAG_WAS_FOLLOWING` key
 455â†’        // was present at all in the Shared Prefs.
 456â†’        // We could have it not set for example in cases where user is upgrading from
 457â†’        // a previous version of the app. In those cases we do not have enough information as of the saved
 458â†’        // tag was a Following tag or not, so (as with empty `DeletablePrefKey.READER_TAG_NAME`)
 459â†’        // let's do not use this piece of information.
 460â†’        String wasFallowingString = getString(DeletablePrefKey.READER_TAG_WAS_FOLLOWING);
 461â†’        if (TextUtils.isEmpty(wasFallowingString)) return null;
 462â†’
 463â†’        wasFollowing = getBoolean(DeletablePrefKey.READER_TAG_WAS_FOLLOWING, false);
 464â†’
 465â†’        return ReaderUtils.getTagFromTagName(tagName, ReaderTagType.fromInt(tagType), wasFollowing);
 466â†’    }
