1010â†’    private static ArrayList<Integer> getRecentlyPickedSiteIds(int limit) {
1011â†’        String idsAsString = getString(DeletablePrefKey.RECENTLY_PICKED_SITE_IDS, "");
1012â†’        String[] items = idsAsString.split(",");
1013â†’
1014â†’        ArrayList<Integer> siteIds = new ArrayList<>();
1015â†’        for (String item : items) {
1016â†’            siteIds.add(StringUtils.stringToInt(item));
1017â†’            if (siteIds.size() == limit) {
1018â†’                break;
1019â†’            }
1020â†’        }
1021â†’
1022â†’        return siteIds;
1023â†’    }
