 468â†’    public static void setReaderTag(ReaderTag tag) {
 469â†’        if (tag != null && !TextUtils.isEmpty(tag.getTagSlug())) {
 470â†’            setString(DeletablePrefKey.READER_TAG_NAME, tag.getTagSlug());
 471â†’            setInt(DeletablePrefKey.READER_TAG_TYPE, tag.tagType.toInt());
 472â†’            setBoolean(
 473â†’                    DeletablePrefKey.READER_TAG_WAS_FOLLOWING,
 474â†’                    tag.isFollowedSites() || tag.isDefaultInMemoryTag()
 475â†’            );
 476â†’        } else {
 477â†’            prefs().edit()
 478â†’                   .remove(DeletablePrefKey.READER_TAG_NAME.name())
 479â†’                   .remove(DeletablePrefKey.READER_TAG_TYPE.name())
 480â†’                   .remove(DeletablePrefKey.READER_TAG_WAS_FOLLOWING.name())
 481â†’                   .apply();
 482â†’        }
 483â†’    }
